// src/components/Footer.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { 
  FaInstagram, FaLinkedin, FaYoutube, FaTiktok, FaSnapchat, 
  FaChevronUp, FaChevronDown 
} from "react-icons/fa";
import { motion, AnimatePresence } from "framer-motion";

const Footer = () => {
  const [expanded, setExpanded] = useState(false);

  return (
    <footer className="fixed bottom-0 left-0 w-full z-50">
      <div className="bg-gray-900 text-white shadow-lg">

        {/* Toggle Bar */}
        <div
          onClick={() => setExpanded(!expanded)}
          className="cursor-pointer flex justify-center items-center py-2 bg-gray-800 hover:bg-gray-700 transition"
        >
          <span className="mr-2 font-semibold tracking-wide">Crafting a Regal Experience</span>
          {expanded ? <FaChevronDown /> : <FaChevronUp />}
        </div>

        {/* Expandable Footer Content */}
        <AnimatePresence>
          {expanded && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 20 }}
              transition={{ type: "spring", stiffness: 120, damping: 20 }}
              className="overflow-hidden"
            >
              <div className="max-w-7xl mx-auto px-6 sm:px-8 lg:px-12 py-8 grid grid-cols-1 md:grid-cols-2 gap-8">

                {/* Quick Links */}
                <div className="flex flex-col space-y-3 text-sm text-gray-300">
                  <h4 className="text-lg font-semibold text-white mb-2">Quick Links</h4>
                  {["Home", "About", "Purpose", "Vision", "Domains", "Team", "Careers", "Contact"].map((name) => (
                    <Link
                      key={name}
                      to={`/${name.toLowerCase() === "home" ? "" : name.toLowerCase()}`}
                      className="relative hover:text-yellow-500 transition group"
                    >
                      {name}
                      <span className="absolute left-0 -bottom-1 w-0 h-[2px] bg-yellow-500 transition-all group-hover:w-full"></span>
                    </Link>
                  ))}
                </div>

                {/* Contact Info + Socials */}
                <div className="flex flex-col space-y-4 md:items-end text-sm text-gray-400">
                  <div>
                    <h4 className="text-lg font-semibold text-white mb-2">Contact</h4>
                    <p>Email: <a href="mailto:aikinannu@gmail.com" className="hover:text-yellow-500">aikinannu@gmail.com</a></p>
                    <p>Phone: <a href="tel:+233557529621" className="hover:text-yellow-500">+233 55 752 9621</a></p>
                  </div>

                  {/* Social Icons */}
                  <div className="flex space-x-4 text-xl">
                    {[FaInstagram, FaLinkedin, FaYoutube, FaTiktok, FaSnapchat].map((Icon, i) => (
                      <motion.a
                        key={i}
                        href="#"
                        target="_blank"
                        rel="noreferrer"
                        whileHover={{ scale: 1.2, color: "#facc15" }} // yellow glow
                        className="transition"
                      >
                        <Icon />
                      </motion.a>
                    ))}
                  </div>
                </div>
              </div>

              {/* Copyright */}
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.2 }}
                className="text-center text-xs text-gray-500 pb-4"
              >
                &copy; {new Date().getFullYear()} Godemar’s Empire. All rights reserved.
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </footer>
  );
};

export default Footer;
